var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"시설의 상황은 어떤가요?","JPN":"施設の状況はどうですか？","ENG":"What's the SITREP on the facility?","TWN":"設施的情況怎麼樣？"},"stage":{"bg":"HELI_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AGENT1_NPC_NULL_NULL","text":{"KOREA":"비전투원은 대피를 마친 상태지만, 패닉룸을 제외한 시설 내부는 침식체에게 완전히 점거되었습니다.","JPN":"非戦闘員は避難しましたが、パニックルーム以外の施設内部は侵食体に占拠されました。","ENG":"The noncombatants have been evacuated, but the interior has been overrun by C.O.s, save for the panic room.","TWN":"非戰鬥人員已經撤離了，除避難屋以外的設施內部，已經完全被侵蝕體佔領了。"},"stage":{"bg":"HELI_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT1_NPC_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L6_1","type":"dialog","speaker":"AGENT1_NPC_NULL_NULL","text":{"KOREA":"현재로선...... 탈출은 고사하고 여기서 계속 버티는 것도 녹록치 않은 상황입니다.","JPN":"現在の状況では……脱出はおろか、ここで耐えるのも容易ではありません。","ENG":"As of now... it'll be a challenge to hold our ground here, let alone escape.","TWN":"現在……別說逃跑了，連繼續堅守這裡都很不容易。"},"stage":{"bg":"HELI_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT1_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"알겠습니다. 곧 도착할 테니 현장에서 뵙죠.","JPN":"わかりました。もうじき到着するので、現場で会いましょう。","ENG":"Understood. I'll be there shortly. See you soon.","TWN":"我知道了。我馬上就到，現場見吧。"},"stage":{"bg":"HELI_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT1_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"AGENT1_NPC_NULL_NULL","text":{"KOREA":"예. 부탁드리겠습니다, 기관장님.","JPN":"はい。よろしくお願いします、機関長。","ENG":"Roger that. We can't wait to see you, Chief.","TWN":"是，拜託您了。機關長。"},"stage":{"bg":"HELI_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT1_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"하 참...... 여긴 무슨 놈의 시설이 툭하면 사고가 터진대?","JPN":"はあ、ったく……この施設、なんでこんなに事故が起きるんだ？","ENG":"Bollocks... Why's this facility involved in some kind of mess all the time?","TWN":"哈啊，真是的……這是什麼鬼設施，怎麼動不動就出事？"},"stage":{"bg":"HELI_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"지은 지도 오래 된 것 같던데, 깔끔하게 새로 만들어서 옮기는 게 낫지 않냐?","JPN":"かなり古いし、別の場所に建て替えた方がいい気がするんだがな。","ENG":"It seems to be pretty old too. Can't you just build a new one elsewhere?","TWN":"好像建立很久了，新建一個乾淨堅固的搬過去不是更好嘛？"},"stage":{"bg":"HELI_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그래요. 당신의 짧은 생각대로 클리포트의 마왕을 동네 창고에 대충 가둬 둘 수 있으면 참 좋겠네요.","JPN":"そうですね。あなたのバカな考えのとおり、\\nクリフォトの魔王を街の倉庫にでも閉じ込められるといいですね。","ENG":"Sure. I bet it'll be a brilliant idea to just keep the Demon Lord of Qliphoth locked up in a neighborhood storage room. You're a genius.","TWN":"是啊，依照你那膚淺的想法，能用村裡的倉庫關住逆卡巴拉魔王的話，真是太好了呢。"},"stage":{"bg":"HELI_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HELI_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"기관의 격리시설은 오래 전 구 관리국의 기술을 빌려 만든 곳이에요.","JPN":"機関の隔離施設は昔、旧管理局の技術で作られたものです。","ENG":"Our quarantine facility was built using the Old Administration's technology.","TWN":"機關的隔離設施，是很久以前借助舊管理局的技術建成的。"},"stage":{"bg":"HELI_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"지금 이 격리시설을 다시 만들 수 있는 기술은 어디에도 없습니다.","JPN":"この隔離施設を作る技術は、今現在どこにも存在しません。","ENG":"Which means the technology to rebuild this facility currently does not exist.","TWN":"現在根本沒有可以重建這種隔離設施的技術。"},"stage":{"bg":"HELI_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"완전히 망가지기 전에 가능한 한 최선을 다해 수리해서 쓸 뿐이죠.","JPN":"完全に崩壊する前に、できる限り最善を尽くして修理するしかないんです。","ENG":"All we can do is keep it repaired to the best of our ability until it's no longer usable.","TWN":"我們只能在徹底毀壞之前，盡全力地維修來延長使用。"},"stage":{"bg":"HELI_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 지금은 기관원들의 생명이 최우선입니다.","JPN":"ですが、今は機関員の命が最優先です。","ENG":"But for now, the lives of our agents take utmost priority.","TWN":"可是現在機關人員的性命最重要。"},"stage":{"bg":"HELI_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"모건과 페리어는 다른 임무로 자리를 비운 상태예요. 우리 둘이서 해결해야 합니다.","JPN":"モーガンとフェリエーは、他の任務で不在です。\\n私たち二人で解決するしかありませんわ。","ENG":"Morgan and Ferrier are currently away on another mission. We'll have to sort this out with just the two of us.","TWN":"摩根和佩里出去執行其他任務了，必須靠我們兩個人解決。"},"stage":{"bg":"HELI_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"핫, 좋아. 그동안의 성과를 똑똑히 보여 주지.","JPN":"はっ、いいぜ。今までの成果を見せてやる。","ENG":"Lovely, then. I'll show you how much I've been improving.","TWN":"哈，好啊。正好讓妳看看我在這段時間取得的成果。"},"stage":{"bg":"HELI_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"훈련 성적은 눈 뜨고 못 봐줄 지경이라던데 자신감 하나는 대단하군요.","JPN":"訓練の成績はズタボロだと伺ったのですが、自信満々ですわね。","ENG":"You sure sound confident, considering how disastrous your training scores are.","TWN":"聽說你的訓練成績差得讓人看不下去，你自己倒是很有自信啊。"},"stage":{"bg":"HELI_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"야, 애초에 훈련 내용 자체가 말도 안 되는 것들이었잖아?","JPN":"おい、そもそも訓練の内容が普通じゃなかっただろ！","ENG":"Oh, come on. The training regimen was absolutely bonkers anyway!","TWN":"喂，當時的訓練內容本身就很不像話好嗎？"},"stage":{"bg":"HELI_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"고층 빌딩 사이를 건너뛰라거나 날아오는 총알을 손으로 잡으라니, 영화를 너무 많이 본 것 아냐?","JPN":"高層ビルと高層ビルの間を飛び越えろとか、銃弾を素手でキャッチしろとか。\\n映画の見すぎじゃないか？","ENG":"Leaping across skyscraper rooftops, catching bullets with bare hands... Someone's been clearly watching too many movies.","TWN":"不是跳躍高樓大廈，就是徒手抓飛行的子彈，電影看太多了是吧？"},"stage":{"bg":"HELI_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"버넷 경의 피를 이은 남자 주제에 변명이 길군요.","JPN":"バーネット卿の血を受け継いだくせに、言い訳がましいですわね。","ENG":"Says the man who's got the blood of Sir Burnett flowing in his veins.","TWN":"身為伯內特卿的子孫可真會狡辯啊。"},"stage":{"bg":"HELI_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐 어쨌든 상관없어요. 오늘 당신의 역할은 견학 같은 거니까요.","JPN":"まあ、何だって構いませんわ。今日のあなたの役目は見学ですから。","ENG":"No matter. For you, this mission is more like a field trip.","TWN":"不過無所謂。今天你要做的就是參觀學習。"},"stage":{"bg":"HELI_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"잘 보고 배우도록 하세요.","JPN":"よく見て学んでください。","ENG":"Just watch and learn.","TWN":"好好看，好好學。"},"stage":{"bg":"HELI_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐? 견학?","JPN":"は？　見学？","ENG":"What? A field trip?","TWN":"什麼？參觀學習？"},"stage":{"bg":"HELI_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"사람을 여기까지 데려와 놓고 뒤에서 구경만 하라는 거야?","JPN":"ここまで連れて来ておいて、見学だと？","ENG":"You bring me all the way out here just so I can watch from behind?","TWN":"把人帶到這裡後就只是讓人在後頭參觀？"},"stage":{"bg":"HELI_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"당연하죠. 갓 걸음마를 뗀 요원을 최전선에서 소모해도 될 만큼 기관이 여유롭지는 않습니다.","JPN":"当然です。やっと二足歩行を始めたエージェントを、最前線で消耗する余裕は本機関にありません。","ENG":"Of course. The Institution can't quite afford to expend a brand new agent whose training wheels just came off.","TWN":"當然了。可不能讓剛學走路的特工死在最前線，機關培養人才並不容易。"},"stage":{"bg":"HELI_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"이것도 훈련의 일환이라고 생각하고 많은 걸 배울 수 있도록 노력하세요.","JPN":"これも訓練の一環だと思って、多くのことを学んでください。","ENG":"Consider this part of your training, and try to learn as much as you can.","TWN":"你就把這當作是訓練的一部分，努力多學一些東西吧。"},"stage":{"bg":"HELI_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L36_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HELI_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"AGENT1_NPC_NULL_NULL","text":{"KOREA":"감사합니다, 기관장님! 와 주셨군요!","JPN":"ありがとうございます、機関長！　来てくださったんですね！","ENG":"Thank you, Chief! You've come for us!","TWN":"謝謝您，機關長！謝謝您能趕來！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT1_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"물론입니다. 기관원들의 생명은 가장 중요한 자산이니까요.","JPN":"もちろんですわ。機関員の命は一番重要な資産ですもの。","ENG":"Of course. Your lives are the most important assets to the Institution.","TWN":"當然了。機關人員的生命可是最重要的財產呢。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT1_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"야, 홍차 폭탄. 둘러 봤는데 다친 사람들이 있긴 해도 큰 부상은 아냐.","JPN":"おい、紅茶爆弾。怪我人はいるが、大したケガじゃない。","ENG":"Oy, Tea Bomb. I took a look around and while there are a few wounded folks, none of them are in critical condition.","TWN":"喂，紅茶炸彈。我查看過了，雖然有些人受了傷，但沒有重傷患。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"늦지 않았군요. 다행이네요.","JPN":"手遅れになる前に到着できたようですね。","ENG":"So we're not too late. Thank goodness.","TWN":"我們沒來遲，實屬萬幸。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT1_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"AGENT1_NPC_NULL_NULL","text":{"KOREA":"그런데, 저...... 기관장님. 잠시 이것 좀 봐 주십시오.","JPN":"ところで……機関長。こちらをご覧ください。","ENG":"By the way, Chief. Please take a look at this.","TWN":"不過……機關長，請您幫忙看看這個。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT1_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L1_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"뭔가요, 이건?","JPN":"何ですか、これは？","ENG":"What is it?","TWN":"這是什麼？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT1_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"AGENT1_NPC_NULL_NULL","text":{"KOREA":"심층부에서 감지 센서가 작동한 기록입니다.","JPN":"深層部で感知センサーが作動した記録です。","ENG":"It's the log of sensor activity down in the deep end.","TWN":"感應器在深層啟動的記錄。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT1_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"AGENT1_NPC_NULL_NULL","text":{"KOREA":"따로 움직이던 직원이라면 괜찮겠지만, 혹시 그 기괴한 침식체라면......","JPN":"別行動をしていた職員だといいのですが、もしあの奇怪な侵食体なら……","ENG":"All this data wouldn't be an issue if it's from our staff down there, but if it's from that freaky C.O.—","TWN":"如果是其他行動的員工那倒還好，但若是那個奇怪的侵蝕體……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT1_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT1_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"물벼룩, 기관장의 명령입니다.","JPN":"ミジンコ、機関長の命令です。","ENG":"Water Flea. This is an order.","TWN":"水蚤，我以機關長的身份命令你。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT1_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"이 분들을 도와 비전투원들을 데리고 시설을 빠져나가도록 하세요.","JPN":"この方々を手伝い、非戦闘員と一緒に施設を出てください。","ENG":"Help these agents evacuate the noncombatants and leave the facility.","TWN":"你幫助這些人，帶著非戰鬥人員逃離設施。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT1_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐? 넌 어쩌려고?","JPN":"はあ？　お前はどうするんだ？","ENG":"What? What are you going to do?","TWN":"什麼？那妳怎麼辦？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"시설 내에 숨어 있는 침식체를 처리해야죠. 내버려 두면 어떤 화근이 될지 모릅니다.","JPN":"施設に隠れている侵食体を始末します。\\n放っておけば、何が起きるかわからないので。","ENG":"I must take down the C.O. hiding in the facility. There's no telling what could come next if we leave it be.","TWN":"當然是處理藏在設施內的侵蝕體了。不解決的話後果不堪想像。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"잠깐, 그런데 혼자 가겠다고? 위험하지 않아?","JPN":"待てよ、お前一人で行くつもりか？　危険だろ？","ENG":"Wait, you're going to go in there by yourself? Isn't it too dangerous?","TWN":"等等，妳難道想一個人去嗎？很危險吧？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"제 실력은 오는 길에 이미 보셨을 텐데요.","JPN":"私の実力は確認済みでしょう？","ENG":"I thought you already saw what I'm capable of on our way here.","TWN":"在來的路上，你不是見識到我的實力了嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"이들과 함께 가세요. 지금 일손이 필요한 곳은 여깁니다.","JPN":"彼らと一緒に行動してください。今、人手が必要な場所はここです。","ENG":"Now go with them. They need your help more than I do right now.","TWN":"你跟他們一起走。現在這邊才更需要人手。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"이런 고집불통 같으니......","JPN":"本当に頑固だな……","ENG":"Stubborn little thing...","TWN":"真是固執……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"흔적은 이곳에서 끊어졌군요.","JPN":"痕跡はここで途切れてますわね。","ENG":"The trails end here.","TWN":"痕跡在這裡斷掉了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"매복인가요? 벌써부터 전술적인 판단을 할 수 있게 됐다니......","JPN":"待ち伏せですか？　こんなに早くから、戦術的な判断を下せるようになるとは……","ENG":"Could this be an ambush? So it can already make tactical choices...","TWN":"是有埋伏嗎？現在已經可以從戰術上做出判斷了……　"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"아마 그 학회장이란 자의 영향일지도 모르겠군요.","JPN":"あの学会長とやらの影響かもしれませんね。","ENG":"Perhaps this is an impact from that President of the Society.","TWN":"說不定是受了那個學會會長的影響。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"이건......?","JPN":"これは……？","ENG":"What's this?","TWN":"這是……？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"......놀래는 방법이 상당히 고전적이시네요. 할로윈은 한참 남았답니다.","JPN":"……驚かせ方が、非常に古典的ですわね。ハロウィンはまだ先でしてよ。","ENG":"What a classic way to scare someone. Unfortunately, Halloween's still a long ways away.","TWN":"……嚇人的方式真是老套。距離萬聖節還很長呢。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"시<color=#ff3636>기가 무</color>르익었<color=#ff3636>다. 정답</color>에 다다라야 한다.","JPN":"機は<color=#ff3636>熟</color>し<color=#ff3636>た。正解に</color>辿り着かなければ。","ENG":"The t<color=#ff3636>ime</color> has c<color=#ff3636>ome. The ans</color>wer must be found.","TWN":"時<color=#ff3636>機成</color>熟<color=#ff3636>了。要找到</color>正確答案。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"멸<color=#ff3636>망으로</color>부터 진<color=#ff3636>리를. 멸</color>망으로부터 계<color=#ff3636>속되</color>는 진리를.","JPN":"滅<color=#ff3636>亡か</color>ら真<color=#ff3636>理を。滅</color>亡から続<color=#ff3636>く</color>真理を。","ENG":"Find the t<color=#ff3636>ruth fro</color>m dest<color=#ff3636>ruction. Find the t</color>ruth that continues fro<color=#ff3636>m dest</color>ruction.","TWN":"從滅<color=#ff3636>亡中</color>找到真<color=#ff3636>理。在滅</color>亡中找到持<color=#ff3636>續的</color>真理。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그 잠깐 사이 이렇게 늘어나다니...... 정말이지 혐오스럽군요.","JPN":"少しの間にここまで増えるなんて……実におぞましいですわ。","ENG":"So you've managed to multiply so much so quickly... How revolting.","TWN":"才這麼一會兒，實力竟然就變強了這麼多……真是噁心。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"흑...... 흐<color=#ff3636>윽......</color>","JPN":"うっ……ぐ<color=#ff3636>すん……</color>","ENG":"Hngh... Hn<color=#ff3636>nngh...</color>","TWN":"嗚……嗚<color=#ff3636>嗚……</color>"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"저<color=#ff3636>기...... 아</color>, 아무<color=#ff3636>도 없</color>어요?","JPN":"あ<color=#ff3636>の……だ</color>、だれ<color=#ff3636>もい</color>ないんですか？","ENG":"I<color=#ff3636>s there.... a-any</color>one th<color=#ff3636>ere?</color>","TWN":"那<color=#ff3636>個……有</color>、有沒有<color=#ff3636>人</color>啊？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"<color=#ff3636>잡아먹</color>힐 거야...... 여<color=#ff3636>기 있으</color>면 나도 다른 사람들처럼......","JPN":"<color=#ff3636>食べられ</color>ちゃう……こ<color=#ff3636>こにいれ</color>ば、他の人たちみたいに……","ENG":"<color=#ff3636>I'll g</color>et eaten... li<color=#ff3636>ke the oth</color>ers, if I stay here...","TWN":"<color=#ff3636>會被</color>吃掉的……待在<color=#ff3636>這裡的</color>話，我也會像其他人一樣……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"잠깐, 그 일을 어떻게......?","JPN":"待って、なぜあの時のことを……？","ENG":"Hang on, how do you know about that?","TWN":"等等，怎麼會這樣……？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"하<color=#ff3636>나</color>...... 가......","JPN":"1<color=#ff3636>つ</color>……が……","ENG":"Fro<color=#ff3636>m one</color>... to...","TWN":"一<color=#ff3636>個</color>……是……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뒤가 텅텅 비었잖아! 뭐 하고 있는 거야?!","JPN":"後ろがガラ空きだ！　ボーっとするな！","ENG":"Watch your six! What do you think you're doing?!","TWN":"妳背後根本就破綻百出嘛，是在幹什麼？！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"물벼룩? 여길 어떻게?","JPN":"ミジンコ？　なぜここに？","ENG":"Water Flea? What are you doing here?","TWN":"水蚤？你怎麼會在這裡？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"이, 이것들 눈 깜짝할 새 불어나네......?","JPN":"こ、こいつら、増えるのめちゃくちゃ早くないか……？","ENG":"These buggers multiply like rabbits, don't they?","TWN":"這、這些東西轉眼間就變大了……？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"홍차 폭탄, 어떻게 하면 돼?!","JPN":"紅茶爆弾、どうすればいい！？","ENG":"What should we do, Tea Bomb?","TWN":"紅茶炸彈，我們該怎麼辦？！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"......격리 시설!","JPN":"……隔離施設！","ENG":"The quarantine facility!","TWN":"……隔離設施！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"저 문으로 밀어 넣으세요! 당신 카운터 능력이라면 가능해요!","JPN":"あの門へ押し込んでください！　あなたのカウンター能力ならできます！","ENG":"Push them into that door! You can do it with your Counter abilities!","TWN":"推進到那個門內！以你制裁者的能力一定可以辦到！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"할 수 있다면 해 봐야지!","JPN":"やるしかない！","ENG":"If you say so!","TWN":"我能做到的話我會試試看！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"간다, 짜식들아! 으랏차아!","JPN":"行くぞ、お前ら！　おりゃああ！","ENG":"Here I come, you little buggers! Haaaaa!","TWN":"上吧，雜碎們！唔喔喔喔！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AGENT1_NPC_NULL_NULL","text":{"KOREA":"전력이 복구됐습니다! 두 분 다 무사하십니까?","JPN":"電力が復旧しました！　お二人とも、ご無事ですか？","ENG":"The power has been restored! Are you both alright?","TWN":"電力恢復了！兩位都沒事吧？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT1_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L32_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"네. 걱정해 줘서 고마워요.","JPN":"はい。心配してくれてありがとうございます。","ENG":"Yes. Thank you for asking.","TWN":"沒事，多謝關心。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT1_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그런데 이 물벼룩은 당신이 보냈나요?","JPN":"ところで、このミジンコはあなたが？","ENG":"Did you send this Water Flea here by the way?","TWN":"不過這水蚤是你派來的嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT1_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"AGENT1_NPC_NULL_NULL","text":{"KOREA":"아, 아뇨. 전력이 끊기자마자 갑자기 기관장님을 찾겠다며 가셨습니다.","JPN":"い、いいえ。電力が切れた途端、急に機関長を探しに行きました。","ENG":"N-no, ma'am. He insisted that he'd go find you as soon as the power went out.","TWN":"不，不是。剛一停電，他就突然說要去找機關長，然後就走了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT1_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT1_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"헹. 걱정해 줘서 고맙다는 말은 아껴 둬. 홍차 폭탄.","JPN":"へッ。感謝の言葉は心にしまっておけ、紅茶爆弾。","ENG":"Heh. Save your thanks for later, Tea Bomb.","TWN":"哼，不用跟我道謝，紅茶炸彈。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"머지 않아 이것 말고도 나에게 고마워할 일들이 수두룩할 테니까.","JPN":"今回以外にも、この先俺に感謝することが山ほどあるはずだからな。","ENG":"You'll have plenty to thank me about from now on.","TWN":"因為在不久的將來，你要感謝我的事會越來越多的。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"......그 근거 없는 자신감은 여전하군요.","JPN":"……その根拠のない自信は相変わらずですわね。","ENG":"I see your baseless self-confidence is as strong as ever.","TWN":"……你這種毫無根據的自信真是沒變啊。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L42_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 확실히 훈련장보다는 실전에 더 어울리는 체질이라는 건 알겠어요.","JPN":"でも、確かに訓練場より実戦に向いている、ということはわかりました。","ENG":"But I do have to admit you're far better suited for actual combat than training.","TWN":"不過比起訓練場，你確實更適合實戰。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L43_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"오, 그래? 드디어 내 실력을 인정하기 시작하는 건가?","JPN":"ほう？　やっと俺の実力を認めるのか？","ENG":"Oh, really? Are you finally going to admit that I'm the man?","TWN":"哦，是嗎？終於開始認同我的實力了嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L44_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"너무 들뜨지 마시죠. 그래 봐야 아직 멀었으니까요.","JPN":"調子に乗らないでください。そうは言っても、まだまだですので。","ENG":"Don't get too excited. You still have long ways to go.","TWN":"別太得意了，儘管如此，你還差得遠呢。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L45_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"쳇. 그래, 그런 식으로 나올 줄 알았어.","JPN":"チッ。そう言うと思ったぜ。","ENG":"Hmpf. I knew you'd be like that.","TWN":"切，是啊，我就知道妳會這麼說。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L46_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"하아. 됐다, 됐어. 용건 다 끝났으면 돌아가기나 해.","JPN":"はあ。もういい。用件も済んだことだし、さっさと帰るぞ。","ENG":"*Sigh* Forget it. Let's just head back if we're done here.","TWN":"唉，算了，算了。事情都辦完了我們就回去吧。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L48_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"확실히...... 버넷 경의 피를 이어받은 건 틀림없나 보군요.","JPN":"確かに……バーネット卿の血を受け継いだのは、間違いないようですね。","ENG":"There's no doubt about it... You are indeed a descendent of Sir Burnett.","TWN":"看來……你的確是伯內特卿的後代沒錯。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"응? 뭐라고 그랬냐? 못 들었어.","JPN":"ん？　何か言ったか？　聞こえなかったぜ。","ENG":"Huh? Did you say something? I didn't catch that.","TWN":"嗯？妳說什麼？我沒聽到。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"아무것도 아니에요. 소음을 잘못 들으셨나 보네요.","JPN":"何でもありません。聞き間違いですわ。","ENG":"It's nothing. You must've heard the engine humming.","TWN":"我什麼都沒說，是你聽錯了吧。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"돌아가죠. 우리들의 본부로.","JPN":"では、帰りましょう。私たちの本部へ。","ENG":"Let's go back then. Back to our HQ.","TWN":"我們回總部吧。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};